%[text] ### Test 2
S01_my_robot;
fprintf('--- TEST 2: 100 Puntos Aleatorios ---\n'); %[output:43ed2f13]
N_test = 100;
q_test_rand = zeros(N_test, 6);

% Generar ángulos aleatorios respetando los límites articulares
for j = 1:6
    q_min = 0.9*Robot.links(j).qlim(1);
    q_max = 0.9*Robot.links(j).qlim(2);
    q_test_rand(:, j) = q_min + (q_max - q_min) * rand(N_test, 1);
end

% Construir el vector_p de entrada
vector_p_rand = zeros(N_test, 6);
Target_poses = Robot.fkine(q_test_rand);

for k = 1:N_test
    vector_p_rand(k, 1:3) = Target_poses(k).t';
    % Extraer Roll, Pitch, Yaw en convención ZYX
    vector_p_rand(k, 4:6) = Target_poses(k).tr2rpy('zyx'); 
end

% Cronometrar
tic;
Q_calc_rand = CinematicaInversa(Robot, vector_p_rand, vector_p_rand(1, :), true);
tiempo_ejecucion = toc;

% Evaluar Error Cartesiano
error_pos_max = 0;
for k = 1:N_test
    T_calc = Robot.fkine(Q_calc_rand(k, :));
    e_pos = norm(Target_poses(k).t - T_calc.t) * 1000; % En milímetros
    if e_pos > error_pos_max
        error_pos_max = e_pos;
    end
end

fprintf('Tiempo de cálculo para %d puntos: %.4f segundos.\n', N_test, tiempo_ejecucion); %[output:1f4976de]
fprintf('Error máximo de posición: %g mm\n', error_pos_max); %[output:6ff486d4]
if error_pos_max < 1e-6 %[output:group:441ccf42]
    fprintf('Resultado: ACEPTABLE.\n\n'); %[output:583acf36]
else
    fprintf('Resultado: INACEPTABLE.\n\n');
end %[output:group:441ccf42]
%[text] ### Test 3
fprintf('--- TEST 3: Brazo completamente estirado ---\n'); %[output:755800f0]
% Valores articulares que estiren el brazo al maximo
q_estirado = deg2rad([0, -75.6, 65.1, 0, 0, 0]);

% Valor articular que da resultado con orientacion coincidente con Z0
% Aunque tecnicamente tambien da el brazo estirado
% q_estirado = deg2rad([0, 16.1, 65.1, 0, 0, 0]);

T_estirado = Robot.fkine(q_estirado);
v_estirado = [T_estirado.t', T_estirado.tr2rpy('zyx')];

Q_calc_estirado = CinematicaInversa(Robot, v_estirado);
T_calc_estirado = Robot.fkine(Q_calc_estirado(1, :)); %[output:66ce9bd6]

e_pos_estirado = norm(T_estirado.t - T_calc_estirado.t) * 1000;
fprintf('Error de posición al límite: %g mm\n\n', e_pos_estirado);
%[text] ### Test 4
fprintf('--- TEST 4: Coordenada Inalcanzable ---\n');
% Pedimos un punto inalcanzable (distancia ~17 [m])
vector_p_imposible = [10, 10, 10, 0, 0, 0]; 

try
    Q_imposible = CinematicaInversa(Robot, vector_p_imposible);
    disp('La función se ejecutó. Verificando manejo de errores.');
catch ME
    fprintf('La función detectó correctamente el error y lanzo un error.\n');
    fprintf('Mensaje de Error: "%s"\n', ME.message);
    fprintf('Resultado: ACEPTABLE.\n');
end
